function formatScoreMetricLocal(key, metric) {
  const value = metricValueLocal(metric);
  if (value === null || value === 0) return null;
  const label = SCORE_METRIC_LABELS_LOCAL[key] || key;
  const unit = metric?.suffix || "";
  const digits = Math.abs(value) >= 100 ? 1 : Math.abs(value) >= 10 ? 1 : 2;
  return `${label}: ${Number(value).toFixed(digits)}${unit}`;
}

function getUsedScoreMetricsLocal(metrics = {}, categories = {}) {
  const used = [];
  for (const [category, keys] of Object.entries(SCORE_CATEGORY_USED_METRICS_LOCAL)) {
    if (scoreValueLocal(categories?.[category]) === null) continue;
    for (const key of keys) {
      const formatted = formatScoreMetricLocal(key, metrics?.[key]);
      if (!formatted) continue;
      used.push({
        key,
        category,
        categoryLabel: SCORE_CATEGORY_LABELS_LOCAL[category] || category,
        label: SCORE_METRIC_LABELS_LOCAL[key] || key,
        value: metricValueLocal(metrics?.[key]),
        suffix: metrics?.[key]?.suffix || "",
        text: formatted,
        meaning: metrics?.[key]?.formula || "",
      });
    }
  }

  const seen = new Set();
  return used.filter((metric) => {
    if (seen.has(metric.key)) return false;
    seen.add(metric.key);
    return true;
  });
}

function buildMetricChipListLocal(metrics = {}, categories = {}, preferredKeys = [], limit = 5) {
  const used = getUsedScoreMetricsLocal(metrics, categories);
  const byKey = new Map(used.map((metric) => [metric.key, metric.text]));
  const chosen = [];
  for (const key of preferredKeys) {
    if (byKey.has(key)) chosen.push(byKey.get(key));
  }
  for (const metric of used) {
    if (chosen.length >= limit) break;
    if (!chosen.includes(metric.text)) chosen.push(metric.text);
  }
  return chosen.slice(0, limit);
}

function fallbackAiScoreSummaryFromReport(report = {}) {
  const categories = report?.grades?.categories || {};
  const metrics = report?.metrics || {};
  const symbol = String(report?.symbol || "This stock").toUpperCase();
  const usedMetrics = getUsedScoreMetricsLocal(metrics, categories).filter((metric) => {
    const value = Number(metric?.value);
    return Number.isFinite(value) && value !== 0;
  });

  const categoryEntries = Object.entries(categories)
    .map(([key, value]) => ({ key, label: SCORE_CATEGORY_LABELS_LOCAL[key] || key, value: scoreValueLocal(value) }))
    .filter((entry) => entry.value !== null && entry.value !== 0)
    .sort((a, b) => b.value - a.value);

  const strongest = categoryEntries.slice(0, 2).map((entry) => entry.label.toLowerCase());
  const weakest = categoryEntries.slice(-2).reverse().map((entry) => entry.label.toLowerCase());
  const metricText = usedMetrics.slice(0, 8).map((metric) => metric.text);
  const firstHalf = metricText.slice(0, 4).join(", ");
  const secondHalf = metricText.slice(4, 8).join(", ");

  const prosSummary = `${symbol} is supported most by ${strongest.join(" and ") || "its strongest operating categories"}. ${firstHalf ? `Key calculation inputs include ${firstHalf}. ` : ""}These figures matter because they show how effectively the business is growing, producing profit, maintaining financial stability, or receiving support from recent market performance. Together, the stronger inputs explain why ${symbol} earns support in the Eval model without relying on any zero-value metric.`;

  const consSummary = `${symbol} is held back most by ${weakest.join(" and ") || "its weaker scoring categories"}. ${secondHalf ? `The main calculation inputs to watch are ${secondHalf}. ` : ""}These measures matter because they show where valuation, balance-sheet flexibility, growth consistency, or market strength may be less favorable than the rest of the report. Those weaker inputs keep the overall profile from looking more complete, while avoiding any metric with a value of zero.`;

  return {
    source: "fallback score breakdown",
    symbol,
    prosSummary,
    consSummary,
    supportSummary: prosSummary,
    holdbackSummary: consSummary,
  };
}

function extractJsonObjectLocal(text = "") {
  const raw = String(text || "").trim();
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {}
  const start = raw.indexOf("{");
  const end = raw.lastIndexOf("}");
  if (start >= 0 && end > start) {
    try {
      return JSON.parse(raw.slice(start, end + 1));
    } catch {}
  }
  return null;
}

async function buildAiScoreSummaryFromReportLocal(report = {}) {
  const fallback = fallbackAiScoreSummaryFromReport(report);
  const apiKey = process.env.OPENAI_API_KEY;
  if (!apiKey) return fallback;

  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), SCORE_BREAKDOWN_TIMEOUT_MS);

  try {
    const profile = report?.profile || {};
    const categories = report?.grades?.categories || {};
    const metrics = report?.metrics || {};
    const news = report?.newsSentiment || {};

    const usedMetrics = getUsedScoreMetricsLocal(metrics, categories);
    const categoryScores = Object.entries(categories || {})
      .map(([key, value]) => ({ key, label: SCORE_CATEGORY_LABELS_LOCAL[key] || key, score: scoreValueLocal(value) }))
      .filter((entry) => entry.score !== null);

    const payload = {
      symbol: report?.symbol,
      companyName: profile?.name,
      industry: profile?.finnhubIndustry,
      companyContext: {
        name: profile?.name,
        ticker: report?.symbol,
        industry: profile?.finnhubIndustry,
        exchange: profile?.exchange,
        country: profile?.country,
      },
      categoryScores,
      usedCalculationMetrics: usedMetrics,
      strengths: report?.strengths || [],
      weaknesses: report?.weaknesses || [],
      newsSummary: news?.summary || news?.overallSummary || "",
      newsArticles: Array.isArray(news?.articles) ? news.articles.slice(0, 3).map((article) => ({
        title: article?.title,
        summary: article?.summary,
        score: article?.score,
        weight: article?.weight,
      })) : [],
    };

    const response = await fetch(OPENAI_CHAT_URL, {
      method: "POST",
      signal: controller.signal,
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: SCORE_BREAKDOWN_MODEL,
        temperature: 0.35,
        max_tokens: 900,
        response_format: { type: "json_object" },
        messages: [
          {
            role: "system",
            content:
              "You write clear, ticker-specific stock-score explanations for Eval. Return only valid JSON. Do not give buy/sell/hold advice. Use the ticker symbol instead of the company name. Never mention missing data, unavailable data, providers, APIs, fallbacks, limitations in data access, or any metric with a numeric value of 0. Only use metrics included in usedCalculationMetrics. Explain each key metric naturally inside the prose and state what it means for this specific stock.",
          },
          {
            role: "user",
            content: `Create exactly two polished summaries for ${report?.symbol}: one Pros summary and one Cons summary. Return JSON with only these keys: prosSummary string, consSummary string.

Rules:
- Use the ticker ${report?.symbol} instead of the company name throughout.
- Each summary should be one substantial, easy-to-read paragraph of about 5-8 sentences.
- The Pros paragraph must explain the strongest parts of the stock's Eval calculation.
- The Cons paragraph must explain the weakest parts of the stock's Eval calculation.
- Mention several important calculation metrics directly inside each paragraph, including their exact non-zero values, and explain in plain English what each metric means and why it helps or hurts ${report?.symbol}.
- ONLY use metrics in usedCalculationMetrics, and completely ignore every metric whose value is 0, null, missing, non-numeric, or unavailable.
- Do not create bullet points, arrays, metric chips, headings, a takeaway, a news section, or a separate overall summary.
- Do not mention the company name, missing data, data quality, providers, APIs, fallbacks, or incomplete coverage.
- Do not repeat category ratings unless you immediately explain them with exact non-zero metric values.
- Do not give buy/sell/hold advice.

Data: ${JSON.stringify(payload)}`,
          },
        ],
      }),
    });

    const json = await response.json().catch(() => null);
    if (!response.ok) {
      console.warn("OpenAI score breakdown failed:", response.status, json?.error?.message || "");
      return fallback;
    }

    const parsed = extractJsonObjectLocal(json?.choices?.[0]?.message?.content);
    if (!parsed || typeof parsed !== "object") return fallback;

    const prosSummary = String(parsed.prosSummary || parsed.supportSummary || fallback.prosSummary || "").trim();
    const consSummary = String(parsed.consSummary || parsed.holdbackSummary || fallback.consSummary || "").trim();

    return {
      source: "OpenAI score breakdown",
      symbol: String(report?.symbol || "").toUpperCase(),
      prosSummary: prosSummary || fallback.prosSummary,
      consSummary: consSummary || fallback.consSummary,
      supportSummary: prosSummary || fallback.prosSummary,
      holdbackSummary: consSummary || fallback.consSummary,
    };
  } catch (error) {
    console.warn("Score breakdown fallback used:", error?.message || error);
    return fallback;
  } finally {
    clearTimeout(timeout);
  }
}


const EVAL_FAQ_KNOWLEDGE = "Eval FAQ knowledge base summary:\n- Eval is a stock-evaluation dashboard, not financial advice.\n- Users search tickers, use Ticker Lookup, save Watchlist stocks, compare 2-5 watchlist stocks, read industry rankings, and ask Eval AI support questions.\n- The backend company universe uses the CSV company universe cached by the backend. It lets users type company names, see tickers on the right, and click a ticker to load the Analyze dashboard.\n- Eval Score is 0.0-10.0 and blends Growth, Profitability, Financial Health, Valuation, Momentum, Pullback, and News Sentiment.\n- Green/yellow/red indicate stronger/mixed/weaker score ranges. Score numbers are educational and not buy/sell/hold recommendations.\n- Metric cards are bar charts from 0-10. Popups/question marks explain category inputs and can be closed with the X button.\n- Price, Momentum, and Pullback use Massive and cache about 1 day.\n- Growth, Profitability, and Financial Health use light FMP/Finnhub fallback and cache about 4 months.\n- Valuation caches about 1 month.\n- Risk and News Sentiment cache about 7 days.\n- Finnhub is used for profile/news and fallback metrics. FMP is used lightly for fundamentals. Massive is used for market data. the embedded CSV company universe is used for ticker/company lookup. OpenAI summarizes/explains support and news.\n- If providers fail, Eval should use fallback providers, cached categories, or the last valid report instead of scoring missing metrics as zero.\n- Watchlist stores saved tickers and powers Compare and stock-specific Eval AI questions.\n- Compare requires 2-5 watchlist stocks and includes clickable radar labels to hide/show tickers.\n- Industry pages show Top 5 peers and use the same cached analysis for each stock. Industry radar labels are clickable.\n- Eval AI should answer all FAQ-style questions about app navigation, dashboard sections, dropdown menu, ticker/company lookup, score rings, metrics, caching, data sources, watchlist, compare, industry rankings, news sentiment, troubleshooting, profile/sign-in basics, terms/contact/support, and loaded/watchlist stocks.\n- Eval AI should not answer unrelated questions outside Eval. Stock-specific questions require the ticker to be loaded on dashboard or saved in watchlist.";

