function getCsvTickerLookupList() {
  return [...CSV_TICKER_LOOKUP].sort((a, b) => String(a.name || "").localeCompare(String(b.name || "")));
}

function normalizeLookupText(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/\+/g, " plus ")
    .replace(/\bcorporation\b/g, "corp")
    .replace(/\bcompany\b/g, "co")
    .replace(/\bincorporated\b/g, "inc")
    .replace(/\blimited\b/g, "ltd")
    .replace(/\btechnologies\b/g, "tech")
    .replace(/\btechnology\b/g, "tech")
    .replace(/\bclass\b/g, "class")
    .replace(/\bplatforms\b/g, "")
    .replace(/\bholdings\b/g, "")
    .replace(/\bgroup\b/g, "")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function compactLookupText(value = "") {
  return normalizeLookupText(value).replace(/\s+/g, "");
}

const COMPANY_INTENT_WORDS =
  /\b(ticker|symbol|stock symbol|stock ticker|what'?s|what is|find|lookup|look up|csv|company|companies|products?|product line|offerings?|makes?|make|manufactures?|manufacture|builds?|build|produces?|produce|sells?|sell|services?|business|description|describe|what does|what do|who is|who are|what kind of|revenue from|known for|main thing|main products?|key products?)\b/i;

const PRODUCT_INTENT_WORDS =
  /\b(products?|product line|offerings?|sells?|sell|makes?|make|manufactures?|manufacture|builds?|build|produces?|produce|services?|what do they sell|what does it sell|what does .* sell|what do .* sell|what do they make|what does it make|what does .* make|key products?|main products?)\b/i;

const DESCRIPTION_INTENT_WORDS =
  /\b(what does|what do|who is|who are|business|description|describe|about|what kind of company|what type of company|what does .* do|what do .* do|known for|explain .* company)\b/i;

function stripTickerQuestionWords(value = "") {
  return normalizeLookupText(value)
    .replace(/\b(what|whats|what s|is|are|the|ticker|symbol|for|of|stock|stocks|company|companies|please|pls|tell|me|find|lookup|look|up|called|name|give|show|does|do|did|they|it|their|its|you|know|a|an|share|shares|equity|listed|traded|csv|file|products|product|offerings|makes|make|manufactures|manufacture|builds|build|produce|produces|sell|sells|services|business|description|describe|about|who|main|key|known|kind|type)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const UPPERCASE_TICKER_STOPWORDS = new Set([
  "A", "AN", "AND", "ARE", "AS", "AT", "BE", "BY", "CAN", "DO", "DOES", "FOR", "FROM",
  "HOW", "I", "IF", "IN", "IS", "IT", "ME", "MY", "OF", "ON", "OR", "THE", "THEIR",
  "THEY", "TO", "WHAT", "WHATS", "WHEN", "WHERE", "WHO", "WHY", "WITH", "YOUR"
]);

function tickerLookupCandidates(query = "") {
  const raw = String(query || "");
  const q = normalizeLookupText(raw);
  const cleaned = stripTickerQuestionWords(raw);
  const compactCleaned = compactLookupText(cleaned);
  const compactRaw = compactLookupText(raw);
  const upperTokens = [...raw.toUpperCase().matchAll(/\b[A-Z]{1,8}(?:\.[A-Z])?\b/g)]
    .map((m) => m[0])
    .filter((token) => !UPPERCASE_TICKER_STOPWORDS.has(token));

  return { raw, q, cleaned, compactCleaned, compactRaw, upperTokens };
}

function scoreTickerLookupItem(item, parts) {
  const symbolRaw = String(item.symbol || "");
  const nameRaw = String(item.name || "");
  const symbol = normalizeLookupText(symbolRaw);
  const name = normalizeLookupText(nameRaw);
  const desc = normalizeLookupText(item.description || "");
  const products = normalizeLookupText(item.products || "");
  const compactSymbol = compactLookupText(symbolRaw);

  const aliases = [
    name,
    name.replace(/\bcorp\b/g, "corporation"),
    name.replace(/\bco\b/g, "company"),
    name.replace(/\binc\b/g, "incorporated"),
    name.replace(/\bltd\b/g, "limited"),
    name.replace(/\btech\b/g, "technology"),
    name.replace(/\btech\b/g, "technologies"),
    name.replace(/\bplatforms\b/g, ""),
    name.replace(/\bgroup\b/g, ""),
    name.replace(/\bholdings\b/g, ""),
    name.replace(/\bcom\b/g, ""),
  ].map(normalizeLookupText).filter(Boolean);

  let score = 0;

  if (parts.upperTokens.includes(symbolRaw)) score += 2500;
  if (symbol === parts.cleaned || symbol === parts.q) score += 2200;
  if (compactSymbol === parts.compactCleaned || compactSymbol === parts.compactRaw) score += 2100;

  for (const alias of aliases) {
    const compactAlias = alias.replace(/\s+/g, "");
    if (alias === parts.cleaned || alias === parts.q) score += 2000;
    if (compactAlias === parts.compactCleaned && parts.compactCleaned.length >= 2) score += 1900;
    if (alias.startsWith(parts.cleaned) && parts.cleaned.length >= 2) score += 1450;
    if (compactAlias.startsWith(parts.compactCleaned) && parts.compactCleaned.length >= 2) score += 1350;
    if (alias.includes(parts.cleaned) && parts.cleaned.length >= 2) score += 1000;
    if (compactAlias.includes(parts.compactCleaned) && parts.compactCleaned.length >= 2) score += 920;
  }

  const queryWords = parts.cleaned.split(" ").filter((word) => word.length >= 2);
  const searchableWords = `${name} ${products} ${desc}`.split(" ");
  if (queryWords.length) {
    const matched = queryWords.filter((word) =>
      searchableWords.some((target) => target === word || target.startsWith(word) || target.includes(word))
    ).length;
    score += matched * 170;
    if (matched === queryWords.length) score += 310;
  }

  if (products.includes(parts.cleaned) && parts.cleaned.length >= 3) score += 410;
  if (desc.includes(parts.cleaned) && parts.cleaned.length >= 3) score += 260;
  if (symbol.startsWith(parts.cleaned) && parts.cleaned.length >= 1) score += 520;
  if (symbol.includes(parts.cleaned) && parts.cleaned.length >= 2) score += 340;

  const nameLengthPenalty = Math.min(name.length, 120) * 0.01;
  return score - nameLengthPenalty;
}

function findCompanyUniverseMatches(question = "", limit = 5) {
  const parts = tickerLookupCandidates(question);
  if (!parts.q) return [];

  const likelyCompanyQuestion = COMPANY_INTENT_WORDS.test(question) || parts.upperTokens.length > 0;
  if (!likelyCompanyQuestion) return [];

  return getCsvTickerLookupList()
    .map((item) => ({ item, score: scoreTickerLookupItem(item, parts) }))
    .filter((entry) => entry.score > 0)
    .sort((a, b) => b.score - a.score || a.item.name.localeCompare(b.item.name))
    .slice(0, limit)
    .map((entry) => entry.item);
}

function formatCompanyUniverseAnswer(match, mode = "ticker") {
  if (!match) return null;
  const products = match.products ? `Products: ${match.products}.` : "";
  const description = match.description ? `${match.description}` : "";

  if (mode === "products") return `${match.symbol} — ${match.name}. ${products || description}`;
  if (mode === "description") {
    const productText = products ? ` ${products}` : "";
    return `${match.symbol} — ${match.name}. ${description}${productText}`.trim();
  }
  if (mode === "both") {
    const productText = products ? ` ${products}` : "";
    return `${match.symbol} — ${match.name}. ${description}${productText}`.trim();
  }
  return `${match.symbol} — ${match.name}`;
}

function findTickerLookupMatches(question = "", limit = 5) {
  return findCompanyUniverseMatches(question, limit);
}


function commonCompanyAliases(value = "") {
  const q = normalizeLookupText(value);
  const compact = compactLookupText(value);

  const aliases = {
    "home depot": "home depot",
    "homedepot": "home depot",
    "the home depot": "home depot",
    "robinhood": "robinhood",
    "robin hood": "robinhood",
    "sofi": "sofi",
    "sofitech": "sofi",
    "sales force": "salesforce",
    "salesforce": "salesforce",
    "amazon": "amazon",
    "apple": "apple",
    "microsoft": "microsoft",
    "nvidia": "nvidia",
    "meta": "meta platforms",
    "facebook": "meta platforms",
    "google": "alphabet",
    "alphabet": "alphabet",
    "tesla": "tesla",
  };

  return aliases[q] || aliases[compact] || q;
}

function extractCompanyQueryParts(question = "") {
  let q = String(question || "");

  // Remove broad request words but keep the company names.
  q = q
    .replace(/\b(what'?s|whats|what is|what are|tell me|give me|show me|find|lookup|look up|stock symbols?|tickers?|ticker symbols?|symbols?|for|of|please|pls)\b/gi, " ")
    .replace(/[?!.]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  // Split on commas, slashes, ampersands, plus signs, and standalone "and".
  const rawParts = q
    .split(/\s*(?:,|\/|\+|&|\band\b)\s*/i)
    .map((part) => commonCompanyAliases(part))
    .map((part) => part.trim())
    .filter((part) => part.length >= 2);

  // Remove accidental junk words.
  const junk = new Set(["ticker", "tickers", "symbol", "symbols", "stock", "stocks", "company", "companies"]);
  const parts = rawParts.filter((part) => !junk.has(part));

  return [...new Set(parts)];
}

function bestSingleCompanyMatch(queryPart = "") {
  const matches = findCompanyUniverseMatches(queryPart, 3);
  if (!matches.length) return null;

  const parts = tickerLookupCandidates(queryPart);
  const scored = matches.map((item) => ({ item, score: scoreTickerLookupItem(item, parts) }))
    .sort((a, b) => b.score - a.score || a.item.name.localeCompare(b.item.name));

  if (!scored.length || scored[0].score <= 0) return null;
  return scored[0].item;
}

function findMultiCompanyTickerAnswer(question = "") {
  if (!/\b(tickers?|symbols?|ticker symbols?|stock symbols?)\b/i.test(question)) return null;

  const queryParts = extractCompanyQueryParts(question);
  if (queryParts.length < 2) return null;

  const matches = [];
  const seenSymbols = new Set();

  for (const part of queryParts) {
    const match = bestSingleCompanyMatch(part);
    if (match && !seenSymbols.has(match.symbol)) {
      seenSymbols.add(match.symbol);
      matches.push(match);
    }
  }

  if (!matches.length) return null;

  return matches.map((match) => `${match.symbol} — ${match.name}`).join("\n");
}

function findTickerLookupAnswer(question = "") {
  const multiAnswer = findMultiCompanyTickerAnswer(question);
  if (multiAnswer) return multiAnswer;

  const matches = findCompanyUniverseMatches(question, 5);
  if (!matches.length) return null;

  const asksProducts = PRODUCT_INTENT_WORDS.test(question);
  const asksDescription = DESCRIPTION_INTENT_WORDS.test(question) && !/\b(ticker|symbol)\b/i.test(question);
  const mode = asksProducts && asksDescription ? "both" : asksProducts ? "products" : asksDescription ? "description" : "ticker";

  if (matches.length === 1) {
    return formatCompanyUniverseAnswer(matches[0], mode);
  }

  const parts = tickerLookupCandidates(question);
  const scored = matches.map((item) => ({ item, score: scoreTickerLookupItem(item, parts) }))
    .sort((a, b) => b.score - a.score || a.item.name.localeCompare(b.item.name));

  // If one match is clearly better, answer it directly.
  if (scored.length >= 2 && scored[0].score >= scored[1].score + 500) {
    return formatCompanyUniverseAnswer(scored[0].item, mode);
  }

  return scored.slice(0, 3).map(({ item }) => formatCompanyUniverseAnswer(item, mode)).join("\n");
}


function normalizeFaqText(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function faqWordSet(value = "") {
  return new Set(
    normalizeFaqText(value)
      .split(" ")
      .filter((word) => word.length >= 2 && !["the", "and", "for", "you", "how", "what", "does", "with", "this", "that", "can", "use", "why", "are", "is", "do", "to"].includes(word))
  );
}

function scoreFaqMatch(question = "", faq = {}) {
  const q = normalizeFaqText(question);
  const fq = normalizeFaqText(faq.question || "");
  const fa = normalizeFaqText(faq.answer || "");
  const fc = normalizeFaqText(faq.category || "");

  if (!q || !fq) return 0;

  let score = 0;

  if (fq === q) score += 1000;
  if (fq.startsWith(q) || q.startsWith(fq)) score += 650;
  if (fq.includes(q) || q.includes(fq)) score += 520;

  const qWords = faqWordSet(question);
  const faqWords = faqWordSet(`${faq.question || ""} ${faq.category || ""}`);
  const answerWords = faqWordSet(faq.answer || "");

  let exactMatches = 0;
  for (const word of qWords) {
    if (faqWords.has(word)) {
      exactMatches += 1;
      score += 85;
    } else if (answerWords.has(word)) {
      score += 42;
    } else {
      for (const fWord of faqWords) {
        if (fWord.startsWith(word) || word.startsWith(fWord)) {
          score += 35;
          break;
        }
      }
    }
  }

  if (qWords.size > 0 && exactMatches / qWords.size >= 0.7) score += 180;
  if (fc && q.includes(fc)) score += 90;

  return score;
}

function findFaqAnswer(question = "") {
  const q = normalizeFaqText(question);
  if (!q) return null;

  const scored = EVAL_FAQ_DATABASE
    .map((faq) => ({ faq, score: scoreFaqMatch(question, faq) }))
    .filter((entry) => entry.score >= 160)
    .sort((a, b) => b.score - a.score || String(a.faq.question).localeCompare(String(b.faq.question)));

  if (!scored.length) return null;

  const best = scored[0];
  const second = scored[1];

  if (best.score >= 330 || !second || best.score >= second.score + 110) {
    return best.faq.answer;
  }

  return null;
}

function localAssistantAnswer(question = "") {
  const companyAnswer = findTickerLookupAnswer(question);
  if (companyAnswer) {
    return {
      answer: companyAnswer,
      source: "csv",
    };
  }

  const faqAnswer = findFaqAnswer(question);
  if (faqAnswer) {
    return {
      answer: faqAnswer,
      source: "faq",
    };
  }

  return null;
}



function normalizeIndustryName(value = "") {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getIndustryKey(industry = "") {
  const clean = normalizeIndustryName(industry);

  for (const [key, terms] of INDUSTRY_ALIASES) {
    if (terms.some((term) => clean.includes(normalizeIndustryName(term)))) {
      return key;
    }
  }

  return Object.keys(INDUSTRY_UNIVERSES).find((key) => normalizeIndustryName(key) === clean) || "Technology";
}

function isValidAnalysisPayload(data) {
  const score = Number(data?.grades?.edgeScore);
  const validCategories = Number(data?.grades?.dataQuality?.validCategoryCount || 0);
  const inputCounts = data?.grades?.dataQuality?.validInputCounts || {};

  const hasEnoughFundamentals =
    Number(inputCounts.growth || 0) >= 2 ||
    Number(inputCounts.profitability || 0) >= 2 ||
    Number(inputCounts.financialHealth || 0) >= 2 ||
    Number(inputCounts.valuation || 0) >= 2;

  const hasMarketData = Number(inputCounts.marketData || 0) >= 2 || Boolean(data?.quote?.c);

  return Number.isFinite(score) && score >= 2 && validCategories >= 5 && hasMarketData && hasEnoughFundamentals;
}

function hoursFromMs(ms) {
  return Number((ms / (60 * 60 * 1000)).toFixed(1));
}

function componentMetaFor(savedAt = {}) {
  return {
    fundamentals: hoursFromMs(COMPONENT_TTLS_MS.fundamentals),
    valuation: hoursFromMs(COMPONENT_TTLS_MS.valuation),
    market: hoursFromMs(COMPONENT_TTLS_MS.market),
    news: hoursFromMs(COMPONENT_TTLS_MS.news),
    risk: hoursFromMs(COMPONENT_TTLS_MS.risk),
    profile: hoursFromMs(COMPONENT_TTLS_MS.profile),
    savedAt,
  };
}

function withCacheInfo(data, cacheInfo, savedAt = {}) {
  return {
    ...data,
    cache: {
      ...(data?.cache || {}),
      ...cacheInfo,
      ttlHours: 24,
      componentTtlsHours: componentMetaFor(savedAt),
    },
  };
}

function isFresh(savedAt, key) {
  const saved = Number(savedAt?.[key] || 0);
  if (!saved) return false;
  return Date.now() - saved < COMPONENT_TTLS_MS[key];
}

function getRefreshPlan(savedAt = {}) {
  return {
    refreshFundamentals: !isFresh(savedAt, "fundamentals"),
    refreshValuation: !isFresh(savedAt, "valuation"),
    refreshMarket: !isFresh(savedAt, "market"),
    refreshNews: !isFresh(savedAt, "news"),
    refreshRisk: !isFresh(savedAt, "risk"),
    refreshProfile: !isFresh(savedAt, "profile"),
  };
}

function allComponentsFresh(plan) {
  return !Object.values(plan).some(Boolean);
}

function scoreToneName(score) {
  const n = Number(score);
  if (!Number.isFinite(n)) return "N/A";
  if (n >= 7.5) return "Strong";
  if (n >= 6.5) return "Mixed";
  return "Weak";
}

function scoreText10(score) {
  const n = Number(score);
  return Number.isFinite(n) ? n.toFixed(1) : "N/A";
}

function availableWeightedAverage(values, fallback = null) {
  let total = 0;
  let weight = 0;

  for (const item of values) {
    const score = Number(item?.score);
    const w = Number(item?.weight);
    if (Number.isFinite(score) && Number.isFinite(w) && w > 0) {
      total += score * w;
      weight += w;
    }
  }

  if (weight === 0) return fallback;
  return Math.max(0, Math.min(10, total / weight));
}

function strongestWeakestFromCategories(categories = {}) {
  const entries = Object.entries(categories)
    .map(([key, value]) => [key, Number(value)])
    .filter(([, value]) => Number.isFinite(value));

  const label = (key) =>
    ({
      growth: "Growth",
      profitability: "Profitability",
      financialHealth: "Financial Health",
      valuation: "Valuation",
      momentum: "Momentum",
      reversal: "Pullback",
      newsSentiment: "News Sentiment",
    }[key] || key);

  if (!entries.length) {
    return { strongest: "Not enough category data yet.", weakest: "Not enough category data yet." };
  }

  const strongest = entries.reduce((best, item) => (item[1] > best[1] ? item : best), entries[0]);
  const weakest = entries.reduce((worst, item) => (item[1] < worst[1] ? item : worst), entries[0]);

  return {
    strongest: `${label(strongest[0])} is the strongest category at ${scoreText10(strongest[1])}/10.`,
    weakest: `${label(weakest[0])} is the weakest category at ${scoreText10(weakest[1])}/10.`,
  };
}

