function cleanSubmittedWeight(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number <= 0) return null;
  return number <= 1 ? number * 100 : number;
}

function cleanSubmittedDollars(value) {
  if (value === null || value === undefined) return null;
  const cleaned = String(value).replace(/[$,%]/g, "").replace(/,/g, "").trim();
  const number = Number(cleaned);
  if (!Number.isFinite(number) || number <= 0) return null;
  return number;
}

const portfolioQuoteCache = new Map();

function portfolioDailyPriceBucket(date = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: "America/New_York",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    hour12: false,
  }).formatToParts(date).reduce((acc, part) => {
    acc[part.type] = part.value;
    return acc;
  }, {});

  const hour = Number(parts.hour);
  const bucketDate = new Date(`${parts.year}-${parts.month}-${parts.day}T12:00:00Z`);
  if (Number.isFinite(hour) && hour < 5) bucketDate.setUTCDate(bucketDate.getUTCDate() - 1);
  return bucketDate.toISOString().slice(0, 10);
}

async function fetchFinnhubPortfolioQuote(symbol, options = {}) {
  const apiKey = process.env.FINNHUB_API_KEY;
  const cleanSymbol = cleanTicker(symbol);
  if (!apiKey || !cleanSymbol) return null;

  const bucket = portfolioDailyPriceBucket();
  const key = `${cleanSymbol}:${bucket}`;
  const cached = portfolioQuoteCache.get(key);
  if (!options.forceRefresh && cached && Number.isFinite(Number(cached.price)) && Number(cached.price) > 0) {
    return Number(cached.price);
  }

  try {
    const url = new URL("https://finnhub.io/api/v1/quote");
    url.searchParams.set("symbol", cleanSymbol);
    url.searchParams.set("token", apiKey);
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), Number(process.env.PROVIDER_TIMEOUT_MS || 3500));
    const response = await fetch(url, { signal: controller.signal });
    clearTimeout(timeout);
    if (!response.ok) {
      if (cached?.price) return Number(cached.price);
      return null;
    }
    const quote = await response.json();
    const current = Number(quote?.c);
    if (Number.isFinite(current) && current > 0) {
      portfolioQuoteCache.set(key, { price: current, fetchedAt: Date.now(), bucket });
      // Keep cache compact: one daily portfolio quote per symbol is enough for the line chart.
      if (portfolioQuoteCache.size > 1000) {
        for (const cacheKey of portfolioQuoteCache.keys()) {
          if (!cacheKey.endsWith(`:${bucket}`)) portfolioQuoteCache.delete(cacheKey);
        }
      }
      return current;
    }
    return cached?.price ? Number(cached.price) : null;
  } catch {
    return cached?.price ? Number(cached.price) : null;
  }
}


const PORTFOLIO_CATEGORY_KEYS = [
  "growth",
  "profitability",
  "financialHealth",
  "valuation",
  "momentum",
  "reversal",
  "newsSentiment",
];

function isSupportedPortfolioStock(report, symbol) {
  const profile = report?.profile || {};
  const name = String(profile?.name || symbol || "").toLowerCase();
  const industry = String(profile?.finnhubIndustry || "").toLowerCase();
  const exchange = String(profile?.exchange || "").toLowerCase();
  const currency = String(profile?.currency || "").toUpperCase();
  const country = String(profile?.country || "").toLowerCase();

  const fundLike = [
    "etf",
    "fund",
    "trust",
    "spdr",
    "ishares",
    "vanguard",
    "invesco qqq",
    "proshares",
    "direxion",
    "ark innovation",
  ];

  const isFundLike = fundLike.some((term) => name.includes(term) || industry.includes(term));
  if (isFundLike) return false;

  if (currency && currency !== "USD") return false;
  if (country && !["us", "usa", "united states", "united states of america"].includes(country)) return false;

  // If Finnhub gives an exchange, keep common U.S.-listed exchanges and OTC; skip clearly foreign exchanges.
  if (exchange) {
    const usExchangeHints = ["nasdaq", "nyse", "amex", "arca", "bats", "otc", "new york", "nms", "ngs", "global select", "capital market"];
    const foreignHints = ["london", "toronto", "hong kong", "shanghai", "shenzhen", "tokyo", "frankfurt", "paris", "milan", "australia", "tsx", "lse", "xetra", "sse", "hkex", "japan"];
    if (foreignHints.some((hint) => exchange.includes(hint)) && !usExchangeHints.some((hint) => exchange.includes(hint))) return false;
  }

  return true;
}

function weightedCategoryScoresFromHoldings(holdings) {
  const result = {};

  for (const key of PORTFOLIO_CATEGORY_KEYS) {
    let weightedTotal = 0;
    let weightTotal = 0;

    for (const holding of holdings) {
      const score = Number(holding?.[key]);
      const weight = Number(holding?.weightPercent);
      if (!Number.isFinite(score) || score <= 0 || !Number.isFinite(weight) || weight <= 0) continue;
      weightedTotal += score * weight;
      weightTotal += weight;
    }

    result[key] = weightTotal > 0 ? Number((weightedTotal / weightTotal).toFixed(1)) : null;
  }

  return result;
}

app.post("/api/portfolio-csv", async (req, res) => {
  try {
    const rows = Array.isArray(req.body?.holdings) ? req.body.holdings : [];
    const submittedPortfolioName = String(req.body?.portfolioName || "Uploaded Portfolio").slice(0, 80);
    const merged = new Map();

    for (const row of rows.slice(0, 250)) {
      const symbol = cleanTicker(row?.symbol || row?.ticker);
      const weightPercent = cleanSubmittedWeight(row?.weightPercent ?? row?.weight ?? row?.holdingPercent ?? row?.holding);
      const holdingDollars = cleanSubmittedDollars(row?.holdingDollars ?? row?.dollars ?? row?.amount ?? row?.marketValue ?? row?.value);
      const shares = cleanSubmittedDollars(row?.shares ?? row?.shareCount ?? row?.quantity ?? row?.qty);
      const averageCost = cleanSubmittedDollars(row?.averageCost ?? row?.avgCost ?? row?.costBasis ?? row?.costPerShare ?? row?.averagePrice);
      if (!symbol) continue;
      if (!/^[A-Z][A-Z0-9.]{0,7}$/.test(symbol)) continue;
      if (weightPercent === null && holdingDollars === null && shares === null) continue;
      const previous = merged.get(symbol) || { symbol, weightPercent: 0, holdingDollars: 0, shares: 0, costTotal: 0 };
      const nextShares = previous.shares + (shares || 0);
      const nextCostTotal = previous.costTotal + ((shares || 0) * (averageCost || 0));
      merged.set(symbol, {
        symbol,
        weightPercent: previous.weightPercent + (weightPercent || 0),
        holdingDollars: previous.holdingDollars + (holdingDollars || 0),
        shares: nextShares,
        costTotal: nextCostTotal,
      });
    }

    let submitted = [...merged.values()].map((row) => ({
      symbol: row.symbol,
      weightPercent: row.weightPercent > 0 ? row.weightPercent : null,
      holdingDollars: row.holdingDollars > 0 ? row.holdingDollars : null,
      shares: row.shares > 0 ? row.shares : null,
      averageCost: row.shares > 0 && row.costTotal > 0 ? row.costTotal / row.shares : null,
    }));

    if (!submitted.length) {
      return res.status(400).json({ error: "No valid ticker and holding rows were found.", route: "api/portfolio-csv" });
    }

    const analyzed = await mapWithConcurrency(submitted, 2, async (row) => {
      try {
        const report = await getCachedAnalysis(row.symbol, { includeAiScoreSummary: false });
        const edgeScore = portfolioScore10(report?.grades?.edgeScore);
        const finnhubCurrentPrice = await fetchFinnhubPortfolioQuote(row.symbol);
        const price = Number(finnhubCurrentPrice || report?.quote?.c);
        if (edgeScore === null || !isSupportedPortfolioStock(report, row.symbol)) {
          return { skipped: true, symbol: row.symbol, reason: "Unsupported or unscored holding." };
        }
        const categories = report?.grades?.categories || {};
        const category = (key) => {
          const score = portfolioScore10(categories?.[key]);
          return score === null || score <= 0 ? null : Number(score.toFixed(1));
        };

        const shares = Number.isFinite(Number(row.shares)) && Number(row.shares) > 0 ? Number(row.shares) : null;
        const averageCost = Number.isFinite(Number(row.averageCost)) && Number(row.averageCost) > 0 ? Number(row.averageCost) : null;
        const currentPrice = Number.isFinite(price) && price > 0 ? Number(price) : null;
        const currentHoldingDollars = shares && currentPrice ? shares * currentPrice : (Number(row.holdingDollars) || null);
        const costBasisDollars = shares && averageCost ? shares * averageCost : null;
        const dollarChange = Number.isFinite(Number(currentHoldingDollars)) && Number.isFinite(Number(costBasisDollars)) && Number(costBasisDollars) > 0
          ? Number(currentHoldingDollars) - Number(costBasisDollars)
          : null;
        const returnPercent = Number.isFinite(Number(dollarChange)) && Number.isFinite(Number(costBasisDollars)) && Number(costBasisDollars) > 0
          ? (Number(dollarChange) / Number(costBasisDollars)) * 100
          : null;

        if (!Number.isFinite(Number(row.weightPercent)) && !Number.isFinite(Number(currentHoldingDollars))) {
          return { skipped: true, symbol: row.symbol, reason: "No current holding value available." };
        }

        return {
          symbol: row.symbol,
          name: report?.profile?.name || row.symbol,
          industry: report?.profile?.finnhubIndustry || "Other",
          inputWeightPercent: Number.isFinite(Number(row.weightPercent)) && Number(row.weightPercent) > 0 ? Number(row.weightPercent) : null,
          holdingDollars: Number.isFinite(Number(currentHoldingDollars)) && Number(currentHoldingDollars) > 0 ? Number(currentHoldingDollars.toFixed(2)) : null,
          costBasisDollars: Number.isFinite(Number(costBasisDollars)) && Number(costBasisDollars) > 0 ? Number(costBasisDollars.toFixed(2)) : null,
          dollarChange: Number.isFinite(Number(dollarChange)) ? Number(dollarChange.toFixed(2)) : null,
          returnPercent: Number.isFinite(Number(returnPercent)) ? Number(returnPercent.toFixed(2)) : null,
          shares: shares ? Number(shares.toFixed(6)) : null,
          averageCost: averageCost ? Number(averageCost.toFixed(4)) : null,
          edgeScore: Number(edgeScore.toFixed(1)),
          price: currentPrice ? Number(currentPrice.toFixed(2)) : null,
          growth: category("growth"),
          valuation: category("valuation"),
          momentum: category("momentum"),
          profitability: category("profitability"),
          financialHealth: category("financialHealth"),
          reversal: category("reversal"),
          newsSentiment: category("newsSentiment"),
          riskLabel: report?.grades?.riskLabel || "N/A",
        };
      } catch (error) {
        return { skipped: true, symbol: row.symbol, reason: error?.message || "Could not analyze ticker." };
      }
    });

    const valid = analyzed.filter((row) => row && !row.skipped);
    const skipped = analyzed.filter((row) => row?.skipped);
    if (!valid.length) {
      return res.status(400).json({ error: "None of the uploaded holdings could be scored yet.", skipped, route: "api/portfolio-csv" });
    }

    const totalCurrentDollars = valid.reduce((sum, row) => sum + (Number(row.holdingDollars) || 0), 0);
    const validInputWeightRaw = valid.reduce((sum, row) => sum + (Number(row.inputWeightPercent) || 0), 0);
    if (totalCurrentDollars <= 0 && validInputWeightRaw <= 0) {
      return res.status(400).json({ error: "The portfolio needs Shares, Holding ($), or Holding % values so Eval can calculate portfolio weights.", route: "api/portfolio-csv" });
    }

    const holdings = valid
      .map((row) => {
        const normalizedWeight = totalCurrentDollars > 0
          ? (Number(row.holdingDollars) || 0) / totalCurrentDollars
          : (Number(row.inputWeightPercent) || 0) / validInputWeightRaw;
        return {
          ...row,
          weightPercent: Number((normalizedWeight * 100).toFixed(2)),
          weightedContribution: Number((row.edgeScore * normalizedWeight).toFixed(2)),
        };
      })
      .filter((row) => row.weightPercent > 0)
      .sort((a, b) => String(a.industry || "").localeCompare(String(b.industry || "")) || b.weightPercent - a.weightPercent);

    const weightedCategoryScores = weightedCategoryScoresFromHoldings(holdings);

    const industryMap = new Map();
    for (const holding of holdings) {
      const industry = holding.industry || "Other";
      if (!industryMap.has(industry)) industryMap.set(industry, []);
      industryMap.get(industry).push(holding);
    }

    const industryGroups = [...industryMap.entries()].map(([industry, groupHoldings]) => {
      const totalWeightPercent = groupHoldings.reduce((sum, row) => sum + row.weightPercent, 0);
      const totalHoldingDollars = groupHoldings.reduce((sum, row) => sum + (Number(row.holdingDollars) || 0), 0);
      const totalCostBasisDollars = groupHoldings.reduce((sum, row) => sum + (Number(row.costBasisDollars) || 0), 0);
      const totalDollarChange = groupHoldings.reduce((sum, row) => sum + (Number(row.dollarChange) || 0), 0);
      const totalReturnPercent = totalCostBasisDollars > 0 ? (totalDollarChange / totalCostBasisDollars) * 100 : null;
      const decorated = groupHoldings
        .map((row) => ({
          ...row,
          industryWeightPercent: totalWeightPercent > 0 ? Number(((row.weightPercent / totalWeightPercent) * 100).toFixed(1)) : null,
        }))
        .sort((a, b) => b.weightPercent - a.weightPercent);

      const industryEvalScore = totalWeightPercent > 0
        ? Number(decorated.reduce((sum, row) => {
            const score = Number(row.edgeScore);
            const industryWeight = Number(row.industryWeightPercent);
            if (!Number.isFinite(score) || score <= 0 || !Number.isFinite(industryWeight) || industryWeight <= 0) return sum;
            return sum + score * (industryWeight / 100);
          }, 0).toFixed(1))
        : null;

      return {
        industry,
        industryEvalScore,
        totalWeightPercent: Number(totalWeightPercent.toFixed(2)),
        totalHoldingDollars: totalHoldingDollars > 0 ? Number(totalHoldingDollars.toFixed(2)) : null,
        totalCostBasisDollars: totalCostBasisDollars > 0 ? Number(totalCostBasisDollars.toFixed(2)) : null,
        totalDollarChange: Number.isFinite(Number(totalDollarChange)) ? Number(totalDollarChange.toFixed(2)) : null,
        totalReturnPercent: Number.isFinite(Number(totalReturnPercent)) ? Number(totalReturnPercent.toFixed(2)) : null,
        holdings: decorated,
      };
    }).sort((a, b) => b.totalWeightPercent - a.totalWeightPercent);

    const portfolioEvalScore = Number(industryGroups.reduce((sum, group) => {
      const score = Number(group.industryEvalScore);
      const weight = Number(group.totalWeightPercent);
      if (!Number.isFinite(score) || score <= 0 || !Number.isFinite(weight) || weight <= 0) return sum;
      return sum + score * (weight / 100);
    }, 0).toFixed(1));

    const industryCount = industryGroups.length;
    const totalCostBasisDollars = holdings.reduce((sum, row) => sum + (Number(row.costBasisDollars) || 0), 0);
    const totalDollarChange = holdings.reduce((sum, row) => sum + (Number(row.dollarChange) || 0), 0);
    const totalReturnPercent = totalCostBasisDollars > 0 ? (totalDollarChange / totalCostBasisDollars) * 100 : null;

    res.json({
      portfolioName: submittedPortfolioName,
      holdings,
      industryGroups,
      skipped,
      summary: {
        portfolioEvalScore,
        weightedCategoryScores,
        submittedHoldingCount: submitted.length,
        scoredHoldingCount: holdings.length,
        voidedHoldingCount: skipped.length,
        totalHoldingDollars: totalCurrentDollars > 0 ? Number(totalCurrentDollars.toFixed(2)) : null,
        totalCostBasisDollars: totalCostBasisDollars > 0 ? Number(totalCostBasisDollars.toFixed(2)) : null,
        totalDollarChange: Number.isFinite(Number(totalDollarChange)) ? Number(totalDollarChange.toFixed(2)) : null,
        totalReturnPercent: Number.isFinite(Number(totalReturnPercent)) ? Number(totalReturnPercent.toFixed(2)) : null,
        industryCount,
      },
      generatedAt: new Date().toISOString(),
      disclaimer: "Educational portfolio score only. Unsupported holdings are excluded, and the weighted Eval Portfolio Score is based on the remaining scorable U.S. stock holdings.",
    });
  } catch (error) {
    console.error("Portfolio CSV route failed:", error?.stack || error?.message || error);
    res.status(500).json({ error: error?.message || "Could not score uploaded portfolio.", route: "api/portfolio-csv" });
  }
});

app.post("/api/assistant", async (req, res) => {
  try {
    const apiKey = process.env.OPENAI_API_KEY;
    const question = String(req.body?.question || "").trim().slice(0, 150);
    const current = req.body?.current || null;
    const watchlist = Array.isArray(req.body?.watchlist) ? req.body.watchlist : [];

    if (!question) {
      return res.status(400).json({ error: "Missing question." });
    }

    const localAnswer = localAssistantAnswer(question);
    if (localAnswer) {
      return res.json({
        answer: localAnswer.answer,
        source: localAnswer.source,
        fallbackUsed: false,
      });
    }

    const allowedWebsiteTerms = [
      "eval",
      "score",
      "power score",
      "stock",
      "ticker",
      "watchlist",
      "price",
      "risk",
      "industry",
      "industries",
      "news",
      "sentiment",
      "growth",
      "profitability",
      "financial health",
      "valuation",
      "momentum",
      "pullback",
      "company",
      "known for",
      "business",
      "what does it make",
      "what do they make",
      "what do they sell",
      "what does it sell",
      "offerings",
      "services",
      "produces",
      "produce",
      "builds",
      "build",
      "manufactures",
      "manufacture",
      "makes",
      "make",
      "selling",
      "sells",
      "sell",
      "product",
      "metric",
      "metrics",
      "category",
      "categories",
      "strong",
      "weak",
      "strongest",
      "weakest",
      "dashboard",
      "website",
      "app",
      "page",
      "button",
      "menu",
      "dropdown",
      "navigate",
      "navigation",
      "how do i",
      "how to",
      "where is",
      "what is",
      "explain",
      "use",
      "using",
      "add",
      "remove",
      "delete",
      "refresh",
      "search",
      "open",
      "click",
      "chart",
      "bar chart",
      "radar",
      "compare",
      "comparison",
      "article",
      "read article",
      "bubble",
      "color",
      "green",
      "yellow",
      "red",
      "rank",
      "ranking",
      "industry ranking",
      "homepage",
      "home",
      "terms",
      "conditions",
      "contact",
      "support",
      "profile",
      "sign in",
      "log in",
      "login",
      "dashboard",
      "clerk",
      "csv",
      "symbol",
      "stock ticker",
      "stock symbol",
      "company name",
      "microsoft",
      "apple",
    ];

    const supportIntentTerms = [
      "how",
      "help",
      "use",
      "navigate",
      "where",
      "what does",
      "what is",
      "explain",
      "show",
      "find",
      "open",
      "click",
      "button",
      "page",
      "menu",
      "dropdown",
      "dashboard",
      "watchlist",
      "compare",
      "metrics",
      "score",
      "industry",
      "news sentiment",
      "risk",
      "price",
      "contact",
      "terms",
      "homepage",
      "profile",
    ];

    const normalizedQuestion = question.toLowerCase();
    const hasWebsiteTerm = allowedWebsiteTerms.some((term) => normalizedQuestion.includes(term));
    const hasSupportIntent = supportIntentTerms.some((term) => normalizedQuestion.includes(term));

    const currentSymbol = String(current?.symbol || current?.profile?.ticker || "").toLowerCase();
    const currentName = String(current?.profile?.name || "").toLowerCase();
    const watchlistSymbols = watchlist
      .map((item) => String(item?.symbol || item?.ticker || "").toLowerCase())
      .filter(Boolean);

    const stockLikeTokens = [...question.toUpperCase().matchAll(/\b[A-Z]{1,5}(?:\.[A-Z])?\b/g)].map((match) => match[0]);
    const allAllowedStockSymbols = [...new Set([currentSymbol, ...watchlistSymbols].filter(Boolean))];
    const mentionedAllowedTicker = stockLikeTokens.some((token) => allAllowedStockSymbols.includes(token.toLowerCase()));

    const mentionsKnownTicker =
      (currentSymbol && normalizedQuestion.includes(currentSymbol)) ||
      watchlistSymbols.some((symbol) => normalizedQuestion.includes(symbol)) ||
      mentionedAllowedTicker;

    const stockAnalysisWords = /\b(should i|buy|sell|hold|invest|investment|target|price target|undervalued|overvalued|better stock|compare|valuation|risk|sentiment|earnings|revenue|profit|growth|momentum|pullback|financial health|metrics?|score|news)\b/i.test(question);
    const asksAboutSpecificStock = stockLikeTokens.length > 0 && stockAnalysisWords;

    const asksGeneralUnrelated =
      /\b(weather|sports score|recipe|movie|music|dating|politics|history homework|essay|song|lyrics|fraternity|hockey|travel|write my|homework answer)\b/i.test(question) &&
      !hasWebsiteTerm &&
      !mentionsKnownTicker;

    if (asksGeneralUnrelated || (!hasWebsiteTerm && !hasSupportIntent && !mentionsKnownTicker && !currentName.includes(normalizedQuestion))) {
      return res.json({
        answer:
          "I can help with Eval support, FAQs, ticker/company lookup, dashboard, metrics, watchlist, compare, news, risk, and loaded/watchlist stocks.",
      });
    }

    if (asksAboutSpecificStock && !mentionsKnownTicker) {
      return res.json({
        answer:
          "Load that ticker or add it to your watchlist first, then ask again.",
      });
    }

    if (!apiKey) {
      return res.status(200).json({
        answer:
          "I checked the local FAQ/company database first. OpenAI fallback needs OPENAI_API_KEY in Render.",
        source: "openai-fallback-unavailable",
        fallbackUsed: true,
      });
    }

    const watchlistContext = watchlist
      .slice(0, 15)
      .map((item) => {
        const symbol = item?.symbol || item?.ticker || "";
        const score = item?.score ?? item?.edgeScore ?? "N/A";
        const strongest = item?.strongest || item?.strength || "N/A";
        const weakest = item?.weakest || item?.weakness || "N/A";
        return `${symbol}: Eval Score ${score}, Strong: ${strongest}, Weak: ${weakest}`;
      })
      .filter(Boolean)
      .join("\n");

    const currentContext = current
      ? JSON.stringify({
          symbol: current.symbol,
          name: current.profile?.name,
          industry: current.profile?.finnhubIndustry,
          price: current.quote?.c,
          dailyChangePercent: current.quote?.dp,
          evalScore: current.grades?.edgeScore,
          risk: current.grades?.riskLabel,
          categories: current.grades?.categories,
          strengths: current.strengths,
          weaknesses: current.weaknesses,
          newsSentiment: current.newsSentiment,
          metrics: current.metrics,
        })
      : "No current stock loaded.";

    const response = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${apiKey}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: process.env.OPENAI_ASSISTANT_MODEL || "gpt-4.1-nano",
        temperature: 0.15,
        max_tokens: 60,
        messages: [
          {
            role: "system",
            content:
              `You are Eval AI, the support assistant inside the Eval stock-evaluation website. Your main job is to help users navigate and understand the app. The backend answers embedded CSV company universe and FAQ questions locally first. You are only the fallback for questions the local FAQ/CSV engine could not confidently answer. You CAN answer questions about the embedded CSV company universe, company-to-ticker/company lookup, ticker-to-company lookup, key products, company descriptions, what a company does, and all Eval FAQs, and all Eval FAQs, how to use the dashboard, ticker/company lookup, search ticker bar, dropdown menu, AI Assistant page, Compare page, Watchlist, industry ranking pages, metric cards, bar charts, radar charts, Eval Score rings, score colors, price/risk cards, data caching, data sources, provider fallbacks, news sentiment, article cards, Terms & Conditions, Contact/Support page, profile/sign-in basics, and how to add, remove, refresh, or compare stocks. You CAN explain what the metrics mean in simple language. You CAN answer stock-specific questions only using the current loaded stock or tickers saved in the user's watchlist context. If a stock is not loaded or in the watchlist, tell the user to load it or add it to the watchlist first. Do NOT answer unrelated questions outside Eval. Do NOT give buy/sell commands or financial advice. Be helpful like a website support agent. Be extremely accurate and short. Prefer one line. For ticker questions, answer only like: AMZN — Amazon.com Inc. Treat sells/makes/builds/manufactures/produces/offers/services/products as product questions. Use the embedded CSV facts. For FAQ/support, answer in 1-2 short sentences. Infer user intent from casual wording. Do not invent CSV facts; if exact company facts are not provided in context, say to load/add the ticker.

FAQ KNOWLEDGE:
${EVAL_FAQ_KNOWLEDGE}`,
          },
          {
            role: "user",
            content: `Question: ${question}\n\nCurrent Eval website stock context:\n${currentContext}\n\nEval website watchlist context:\n${watchlistContext || "No watchlist context."}`,
          },
        ],
      }),
    });

    const json = await response.json().catch(() => null);

    if (!response.ok) {
      console.error("OpenAI assistant failed:", response.status, json?.error?.message || "");
      return res.status(200).json({
        answer:
          "I checked the local FAQ/company database first. OpenAI fallback is unavailable right now.",
        source: "openai-fallback-error",
        fallbackUsed: true,
      });
    }

    const answer = json?.choices?.[0]?.message?.content?.trim();

    return res.json({
      answer:
        answer ||
        "I can help with Eval support, FAQs, ticker/company lookup, dashboard, metrics, watchlist, compare, news, risk, and loaded/watchlist stocks.",
      source: "openai-fallback",
      fallbackUsed: true,
    });
  } catch (error) {
    console.error("Assistant route failed:", error?.stack || error?.message || error);
    return res.status(500).json({
      error: error?.message || "Assistant route failed.",
      route: "api/assistant",
    });
  }
});


